# -*- coding: utf-8 -*-

"""
Bootstrap d'installation (fichier unique)
- Crée la structure de projet et tous les catalogues requis
- Alimente le catalogue central des vecteurs (chaque objet a son vecteur)
- Déclare les relations snake_case (depends_on, result_of, type_of, instance_of, element_of)
- Déploie un mini serveur HTTP intégré et ouvre la page de configuration
"""

import os, json, pathlib, datetime, threading, webbrowser, socket
from http.server import HTTPServer, SimpleHTTPRequestHandler
from urllib.parse import urlparse, parse_qs

# ======================================================================
# Réglages de base
# ======================================================================

BASE = pathlib.Path(__file__).resolve().parent
CAT = BASE / "catalogs"
WWW = BASE / "www"
CFG = BASE / "config"
NOW = datetime.datetime.utcnow().isoformat() + "Z"

PORT = int(os.environ.get("BOOTSTRAP_PORT", "8000"))
HOST = "127.0.0.1"

# ======================================================================
# Helpers
# ======================================================================

def ensure_dirs():
    for p in [CAT, WWW, CFG]:
        p.mkdir(parents=True, exist_ok=True)

def write_json(path: pathlib.Path, payload):
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")

def load_json(path: pathlib.Path, default):
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return default

def upsert_array(array, ident, entry):
    """array: list of entries ; each entry stores ident at entry['identity']['definitions']['ident']"""
    idx = None
    for i, e in enumerate(array):
        cur = (((e.get("identity") or {}).get("definitions") or {}).get("ident"))
        if cur == ident:
            idx = i
            break
    if idx is None:
        array.append(entry)
    else:
        array[idx] = entry

def mk_identity(ident, name_fr, desc_fr, type_str, vector_ident, extra_defs=None):
    defs = {
        "ident": ident,
        "name": {"FR": name_fr},
        "description": {"FR": desc_fr},
        "version": "",
        "question": "",
        "validation_methods": [],
        "relation": {},
        "type": type_str,
        "created_at": NOW,
        "created_by": "bootstrap",
        "vector": vector_ident
    }
    if extra_defs:
        defs.update(extra_defs)
    return {
        "rules": {},
        "options": {},
        "definitions": defs
    }

def mk_node(definitions=None):
    return {
        "rules": {},
        "options": {},
        "definitions": definitions or {}
    }

# ======================================================================
# Seeds (catalogues)
# ======================================================================

def seed_vectors():
    """Catalogue central : tous les objets doivent y figurer."""
    path = CAT / "vectors_catalog.json"
    data = load_json(path, [])

    # Vecteurs de base
    core_vec = {
        "identity": mk_identity(
            "core_vector", "Vecteur — Core",
            "Vecteur de base pour les objets du système.",
            "vector", "core_vector"
        ),
        "view": mk_node(), "context": mk_node()
    }
    agency_vec = {
        "identity": mk_identity(
            "agency_vector", "Vecteur — Agence",
            "Vecteur pour l’objet Agence.",
            "vector", "agency_vector"
        ),
        "view": mk_node(), "context": mk_node()
    }
    relation_vec = lambda name: {
        "identity": mk_identity(
            f"{name}_vector", f"Vecteur — {name}",
            f"Vecteur associé à la relation {name}.",
            "vector", f"{name}_vector"
        ),
        "view": mk_node(), "context": mk_node()
    }
    scenario_vec = {
        "identity": mk_identity(
            "bootstrap_scenario_vector", "Vecteur — bootstrap_scenario",
            "Vecteur pour le scénario d’amorçage.",
            "vector", "bootstrap_scenario_vector"
        ),
        "view": mk_node(), "context": mk_node()
    }
    server_vec = {
        "identity": mk_identity(
            "server_vector", "Vecteur — Serveur",
            "Vecteur pour l’objet serveur/config.",
            "vector", "server_vector"
        ),
        "view": mk_node(), "context": mk_node()
    }

    for v in [
        core_vec, agency_vec, scenario_vec, server_vec,
        relation_vec("depends_on"),
        relation_vec("result_of"),
        relation_vec("type_of"),
        relation_vec("instance_of"),
        relation_vec("element_of"),
    ]:
        ident = v["identity"]["definitions"]["ident"]
        upsert_array(data, ident, v)

    write_json(path, data)

def seed_relations():
    """Relations canoniques (snake_case)."""
    path = CAT / "relations_catalog.json"
    data = load_json(path, [])

    def rel_entry(ident, name_fr, desc_fr):
