# ======================================================================
# Serveur HTTP minimal (stdlib)
# ======================================================================

class BootstrapHandler(SimpleHTTPRequestHandler):
    def _set_headers(self, status=200, ctype="application/json; charset=utf-8"):
        self.send_response(status)
        self.send_header("Content-Type", ctype)
        self.send_header("Cache-Control", "no-store")
        self.end_headers()

    def do_GET(self):
        parsed = urlparse(self.path)
        if parsed.path in ("/", "/index.html", "/config"):
            index = WWW / "index.html"
            if not index.exists():
                self._set_headers(404); self.wfile.write(b"Missing index.html"); return
            self._set_headers(200, "text/html; charset=utf-8")
            self.wfile.write(index.read_bytes()); return

        if parsed.path == "/api/catalogs":
            cats = []
            for p in CAT.glob("*_catalog.json"):
                cats.append(p.name)
            self._set_headers(200)
            self.wfile.write(json.dumps({"catalogs": cats}, ensure_ascii=False).encode("utf-8"))
            return

        if parsed.path == "/health":
            self._set_headers(200); self.wfile.write(b"ok"); return

        # static fallback
        return super().do_GET()

    def do_POST(self):
        parsed = urlparse(self.path)
        if parsed.path == "/api/config":
            length = int(self.headers.get("Content-Length", "0"))
            body = self.rfile.read(length) if length else b"{}"
            try:
                data = json.loads(body.decode("utf-8"))
            except Exception:
                self._set_headers(400); self.wfile.write(b"Invalid JSON"); return

            # Écrit la config
            cfg = {
                "db": {"kind": data.get("db") or "sqlite", "dsn": data.get("dsn") or ""},
                "admin": {"email": data.get("admin_email") or "", "password": data.get("admin_password") or ""},
                "written_at": NOW
            }
            write_json(CFG / "config.json", cfg)
            self._set_headers(200)
            self.wfile.write(json.dumps({"status":"ok","config":cfg}, ensure_ascii=False).encode("utf-8"))
            return

        self._set_headers(404); self.wfile.write(b"Not found")

def run_server():
    httpd = HTTPServer((HOST, PORT), BootstrapHandler)
    print(f"[server] listening on http://{HOST}:{PORT}")
    httpd.serve_forever()

